import{_ as e,o as i,c as a,ai as r}from"./chunks/framework.CaiDwmc7.js";const m=JSON.parse('{"title":"AI 探索（独立模块）","description":"","frontmatter":{},"headers":[],"relativePath":"ai/index.md","filePath":"ai/index.md"}'),t={name:"ai/index.md"};function o(n,l,s,g,d,h){return i(),a("div",null,[...l[0]||(l[0]=[r('<h1 id="ai-探索-独立模块" tabindex="-1">AI 探索（独立模块） <a class="header-anchor" href="#ai-探索-独立模块" aria-label="Permalink to “AI 探索（独立模块）”">​</a></h1><blockquote><p>这里是专门给自己的 <strong>AI / 大模型学习、探索热门工具与开源项目</strong> 留的空间，不再和传统「Java / 数据库 / 框架」技术库混在一起，方便单独规划。<br><strong>命名说明</strong>：顶栏使用 <strong>「AI 探索」</strong>——模块内仍包含<strong>阶段路线与循序渐进</strong>（偏系统学习）与<strong>热门软件与开源生态地图</strong>（偏工具与选型），避免旧名「AI 开发」过于像岗位职责描述。</p></blockquote><hr><h2 id="🔥-热门-ai-软件与开源项目-探索入口" tabindex="-1">🔥 热门 AI 软件与开源项目（探索入口） <a class="header-anchor" href="#🔥-热门-ai-软件与开源项目-探索入口" aria-label="Permalink to “🔥 热门 AI 软件与开源项目（探索入口）”">​</a></h2><p>想先看「当下都在用什么、该 Star 谁」——从这里进入：</p><ul><li><a href="/ai/explore/"><strong>AI 热门软件与开源项目地图</strong></a>：按 <strong>对话与编程辅助、本地推理、Agent 编排、RAG、推理服务、多模态</strong> 等维度整理，附学习优先级与站内文档跳转。</li></ul><hr><h2 id="🧭-从哪里开始看" tabindex="-1">🧭 从哪里开始看？ <a class="header-anchor" href="#🧭-从哪里开始看" aria-label="Permalink to “🧭 从哪里开始看？”">​</a></h2><p>如果你现在只是普通开发，希望<strong>先用好大模型 + 慢慢往 AI 工程靠拢</strong>，可以按下面顺序：</p><ol><li><strong>总览路线图</strong><ul><li><a href="/ai/ai-roadmap.html">AI 时代开发者入门路线（LLM / Agent / 多模态 / MLOps）</a></li></ul></li><li><strong>阶段一：用好大模型（效率为主）</strong><ul><li><a href="/ai/llm-basics.html">第一阶段：大模型（LLM）入门与 Prompt 规划【效率优先】</a></li></ul></li><li><strong>阶段一进阶：让模型“能干活”</strong><ul><li><a href="/ai/agent-basics.html">第一阶段进阶：Agent / 工具型 AI 规划【让模型“能干活”】</a></li></ul></li><li><strong>阶段二：MVP Server / 数据中台</strong><ul><li><a href="/ai/mvp-server.html">第二阶段：MVP Server / 数据中台规划【让模型吃到“干净数据”】</a></li></ul></li><li><strong>阶段三：RAG / 多模态 / 知识图谱（进阶可选）</strong><ul><li><a href="/ai/multimodal-kg.html">第三阶段：多模态 &amp; 知识图谱规划【做更“聪明”的知识助手】</a></li></ul></li><li><strong>阶段四：部署 &amp; MLOps（后期选修）</strong><ul><li><a href="/ai/mlops-platform.html">第四阶段（可选）：部署 &amp; MLOps 规划【从 Demo 走向“小产品”】</a></li></ul></li></ol><hr><h2 id="📚-三个阶段的「模块化文章」版-一步步学" tabindex="-1">📚 三个阶段的「模块化文章」版（一步步学） <a class="header-anchor" href="#📚-三个阶段的「模块化文章」版-一步步学" aria-label="Permalink to “📚 三个阶段的「模块化文章」版（一步步学）”">​</a></h2><p>如果你更希望<strong>按文章顺序一步步练</strong>（每篇都有练习/验收点），从这里进入：</p><ol><li><strong>阶段一模块：LLM &amp; Prompt（循序渐进）</strong><ul><li><a href="/ai/stage-1-llm/">模块导航：阶段一（LLM &amp; Prompt）</a></li></ul></li><li><strong>阶段二模块：Agent &amp; Tools（循序渐进）</strong><ul><li><a href="/ai/stage-2-agent/">模块导航：阶段二（Agent &amp; Tools）</a></li></ul></li><li><strong>阶段三模块：MVP Server / 数据中台（循序渐进）</strong><ul><li><a href="/ai/stage-3-mvp-server/">模块导航：阶段三（MVP Server）</a></li></ul></li></ol><hr><h2 id="🧩-大模型部署及使用-本地-云端" tabindex="-1">🧩 大模型部署及使用（本地/云端） <a class="header-anchor" href="#🧩-大模型部署及使用-本地-云端" aria-label="Permalink to “🧩 大模型部署及使用（本地/云端）”">​</a></h2><ul><li><a href="/ai/model-deploy/">模块导航：大模型部署及使用</a><ul><li><a href="/ai/model-deploy/01-local-deploy.html">本地部署</a></li><li><a href="/ai/model-deploy/02-cloud-deploy.html">云端部署</a></li><li><a href="/ai/model-deploy/03-model-selection.html">模型选择指南（按环境/场景）</a></li><li><a href="/ai/model-deploy/04-runtime-compare.html">推理框架/工具对比与选型（2026）</a></li></ul></li></ul><hr><h2 id="🧪-面向-agent-开发入门-的专属学习路径" tabindex="-1">🧪 面向“Agent 开发入门”的专属学习路径 <a class="header-anchor" href="#🧪-面向-agent-开发入门-的专属学习路径" aria-label="Permalink to “🧪 面向“Agent 开发入门”的专属学习路径”">​</a></h2><blockquote><p>目标很具体：<strong>从现在的 Java 开发 → 能独立做出 1～2 个可用的 AI Agent 小工具</strong>，优先服务你自己的“面试学习 / 知识库”场景。</p></blockquote><h3 id="第-0-阶段-打基础-llm-使用-prompt" tabindex="-1">第 0 阶段：打基础（LLM 使用 + Prompt） <a class="header-anchor" href="#第-0-阶段-打基础-llm-使用-prompt" aria-label="Permalink to “第 0 阶段：打基础（LLM 使用 + Prompt）”">​</a></h3><ul><li><strong>用时建议</strong>：1～3 天，和日常写代码/复习穿插进行。</li><li><strong>要做到：</strong><ul><li>会在网页端稳定使用 1～2 个大模型，帮你改代码、解释报错、整理面试题。</li><li>按 <code>llm-basics</code> 里的模板，整理出<strong>自己的 Prompt 模板库</strong>（面试 Q&amp;A、学习总结、自我介绍生成等）。</li></ul></li><li><strong>对应文档：</strong><ul><li><code>/tech-system/ai/llm-basics</code></li></ul></li></ul><h3 id="第-1-阶段-单-agent-单工具-最小闭环" tabindex="-1">第 1 阶段：单 Agent + 单工具（最小闭环） <a class="header-anchor" href="#第-1-阶段-单-agent-单工具-最小闭环" aria-label="Permalink to “第 1 阶段：单 Agent + 单工具（最小闭环）”">​</a></h3><ul><li><strong>用时建议</strong>：3～7 天。</li><li><strong>核心目标：</strong> 做出一个“<strong>单 Agent + 一个外部工具</strong>”的小项目，比如： <ul><li>“面试学习助手”： <ul><li>工具：读取本地 Markdown（你现在这个 VitePress 库里的某个模块）。</li><li>能力：输入模块名 → 生成 N 道面试题 + 参考答案 → 写回新的 Markdown。</li></ul></li></ul></li><li><strong>学习要点：</strong><ul><li>读完 <code>/tech-system/ai/agent-basics</code> 中的： <ul><li>System/User Prompt</li><li>Tools / Function Calling</li><li>最小 Demo 建议</li></ul></li><li>选一门你顺手的语言（推荐 Java / Node / Python 任一），手写出： <ul><li>“调用 LLM + 调用一个 HTTP / 本地文件工具”的最小 Agent 流程。</li></ul></li></ul></li><li><strong>对应文档：</strong><ul><li><code>/tech-system/ai/agent-basics</code></li><li><code>/tech-system/ai/phase1-llm-agent</code>（更细的阶段一学习规划）</li></ul></li></ul><h3 id="第-2-阶段-mvp-server-简单-rag-让-agent-吃对数据" tabindex="-1">第 2 阶段：MVP Server + 简单 RAG（让 Agent“吃对数据”） <a class="header-anchor" href="#第-2-阶段-mvp-server-简单-rag-让-agent-吃对数据" aria-label="Permalink to “第 2 阶段：MVP Server + 简单 RAG（让 Agent“吃对数据”）”">​</a></h3><ul><li><strong>用时建议</strong>：1～3 周，可拆成零散小任务。</li><li><strong>核心目标：</strong><ul><li>做出一个<strong>小型数据中台（MVP Server）</strong>，专门给 Agent 提供“整理好的上下文”。</li><li>让 Agent 不再直接读文件，而是<strong>先调你的中台，再调模型</strong>。</li></ul></li><li><strong>推荐实战：</strong><ul><li>用 Spring Boot 做一个 <code>/context</code> 接口： <ul><li>从 <code>docs/</code> 目录扫描 Markdown，抽取标题/小节/标签。</li><li>按模块返回一批“待学习内容 + 简要摘要”。</li></ul></li><li>在 Agent 侧改成： <ul><li>用户输入模块名 → 先调 <code>/context</code> → 再调 LLM 生成学习计划/面试题。</li></ul></li></ul></li><li><strong>对应文档：</strong><ul><li><code>/tech-system/ai/mvp-server</code></li><li><code>/tech-system/ai/phase2-mvp-server</code></li></ul></li></ul><h3 id="第-3-阶段-进阶-rag-多知识源-agent" tabindex="-1">第 3 阶段（进阶）：RAG + 多知识源 Agent <a class="header-anchor" href="#第-3-阶段-进阶-rag-多知识源-agent" aria-label="Permalink to “第 3 阶段（进阶）：RAG + 多知识源 Agent”">​</a></h3><ul><li><strong>用时建议</strong>：2～4 周，完全可分散推进。</li><li><strong>核心目标：</strong><ul><li>让 Agent 能基于<strong>向量检索</strong>从你的面试笔记库中找资料，再生成答案。</li><li>初步理解“多工具、多步任务”的 Agent 流程。</li></ul></li><li><strong>推荐实战：</strong><ul><li>选一个向量库（本地/云端皆可），把 <code>Java / 数据库 / Redis</code> 三个模块做成向量化知识库。</li><li>写一个 “面试问答 Agent”： <ul><li>输入：问题 + 模块（如“数据库”）。</li><li>步骤：向量检索 → 拼上下文 → 调 LLM → 输出答案 + 引用。</li></ul></li><li>有余力再尝试：把“行情 / 新闻”等外部 API 加进来，做多工具 Agent。</li></ul></li><li><strong>对应文档：</strong><ul><li><code>/tech-system/ai/multimodal-kg</code></li><li><code>/tech-system/ai/phase3-multimodal-kg</code></li></ul></li></ul><h3 id="第-4-阶段-可选-部署成-给别人用-的小服务" tabindex="-1">第 4 阶段（可选）：部署成“给别人用”的小服务 <a class="header-anchor" href="#第-4-阶段-可选-部署成-给别人用-的小服务" aria-label="Permalink to “第 4 阶段（可选）：部署成“给别人用”的小服务”">​</a></h3><ul><li><strong>用时建议</strong>：按兴趣慢慢来，完全可选。</li><li><strong>核心目标：</strong><ul><li>把你做好的 Agent / 学习助手，用 Docker + 简单部署方式放到公网或内网。</li><li>会画一张简易架构图，方便写进简历或在面试里讲。</li></ul></li><li><strong>对应文档：</strong><ul><li><code>/tech-system/ai/mlops-platform</code></li><li><code>/tech-system/ai/phase4-mlops-platform</code></li></ul></li></ul><blockquote><p>总结一句：<strong>先 LLM → 再单工具 Agent → 再 MVP Server → 再 RAG Agent → 最后看部署</strong>。<br> 每一阶段都尽量做出<strong>能服务你现在“面试学习/知识整理”主线的 Agent 小工具</strong>，这样学 AI 不会和你当前求职目标脱节。</p></blockquote><hr><h2 id="🎯-模块定位-和技术库分开的原因" tabindex="-1">🎯 模块定位：和技术库分开的原因 <a class="header-anchor" href="#🎯-模块定位-和技术库分开的原因" aria-label="Permalink to “🎯 模块定位：和技术库分开的原因”">​</a></h2><ul><li><strong>技术库</strong>：更多是 Java / 数据库 / Redis / 框架 等传统知识点，偏“面试 &amp; 基础能力”。</li><li><strong>AI 模块</strong>：专门围绕 <strong>LLM / Agent / RAG / 部署 &amp; MLOps</strong>，规划「从普通开发 → 能上手 AI 工程与产品」的路线。</li></ul><p>以后和 AI 有关的新内容（如：本地大模型部署、Agent 实战、知识库问答项目等），统一放在这个模块下，方便单独规划与回顾。</p><hr><h2 id="🔗-关联模块" tabindex="-1">🔗 关联模块 <a class="header-anchor" href="#🔗-关联模块" aria-label="Permalink to “🔗 关联模块”">​</a></h2><ul><li>技术体系总览：<code>/tech-system/</code></li><li>开源项目中的 AI &amp; 大模型实践：<code>/open-source/ai-projects</code>、<code>/open-source/llm-projects</code></li></ul>',38)])])}const u=e(t,[["render",o]]);export{m as __pageData,u as default};
